import React from "react";
import { useState } from "react";
import "./nav.css";

export default function Nav() {
  const [Active, IsActive] = useState("off");
  const [Style, setStyle] = useState("pushMenu1");

  const handleClick = () => {
    if (Active === "off") {
      IsActive("true");
      setStyle("");
      console.log(Style);
    } else {
      IsActive("off");
      setStyle("pushMenu");
      console.log(Style);
    }
  };

  return (
    <div>
      <div className={Style}></div>
      <div onClick={handleClick} className="gg-menu-grid-o"></div>
    </div>
  );
}

